import Typography from '@mui/material/Typography'
import Card from '@mui/material/Card'
import {Link} from 'react-router-dom'

function MenuCourseCard(props) {
    return (
        <Link to={props.courseUrl ? 'cours/' + props.courseUrl : '404'} style={{ textDecoration: 'none' }}>
            <Card variant='elevation' elevation={6} style={{ padding: '5px' }}>
                <Typography variant='subtitle2'>
                    {props.courseName}
                </Typography>
                {props.hideDetails ?
                    null : <Typography variant='body1'>
                        {props.institution || 'Cégep de Victoriaville'} | {props.acronym}
                    </Typography>
                }
            </Card>
        </Link>
    )
}

export default MenuCourseCard;