import { Grid, Stack, Typography } from "@mui/material";
import React, { useEffect, useState } from "react";
import Question from "./Question";
import { useParams } from "react-router-dom";

function Quiz(props) {
    const { courseUrl, lessonUrl } = useParams()
    const [error, setError] = useState(null)
    const [quizContent, setQuizContent] = useState(null)
    const [loading, setLoading] = useState(true)
    const [nbCorrectAnswer, setNbCorrectAnswer] = useState(0)

    const onQuestionAnswered = (answerType, correctlyAnswererBefore) => {
        const changeFromAnswer = answerType ? 1 : 0
        const changeFromPrevious = correctlyAnswererBefore || answerType ? 0 : -1

        setNbCorrectAnswer(changeFromAnswer + changeFromPrevious + nbCorrectAnswer)
    }

    useEffect(() => {
        try {
            const file = require('../data/' + courseUrl + '/' + lessonUrl + '.txt')

            fetch(file)
                .then(response => response.json())
                .then(text => setQuizContent(text))
                .catch(e => setError(e))
        } catch (exception) {
            setError(exception.message)
        }

        setLoading(false)
    }, [courseUrl, lessonUrl])

    if (loading) {
        return <Typography>En chargement</Typography>
    }
    else if (error || quizContent === null) {
        return <Typography>{error}</Typography>
    } else {
        return (
            <Stack spacing={2}>
                <Typography variant='h5'>Testez vos apprentissages</Typography>
                <Grid container>
                    {quizContent.questions.map((element, idx) => <Question key={idx} questionData={element} darkTheme={props.darkTheme}
                        onQuestionAnswered={onQuestionAnswered}/>)}
                </Grid>
                <Typography variant='subtitle2'>Votre résultat : {nbCorrectAnswer} / {quizContent.questions.length}</Typography>
            </Stack>
        )
    }
}

export default Quiz;

