import { Card, Typography, Grid, Stack, Divider, Box } from "@mui/material";
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import {Link} from 'react-router-dom'
import TaskAltRoundedIcon from "@mui/icons-material/TaskAltRounded";

function LessonCard(props) {
    console.log(props.complete === true)

    return (
        <Grid item xs={4}>
            <Link to={props.lessonURL || '404'} style={{color:'inherit', textDecoration:'none'}}>
                <Card style={{padding:'5px', display:'flex', flexFlow: 'column', height:'100%'}} elevation={6}>
                    <Typography variant="h6">
                        {props.title || 'Nommez-moi SVP !'}
                    </Typography>
                    <Divider style={{marginBottom:'10px'}}/>
                    <Typography variant="body1" sx={{flex: '1 1 auto'}}>
                        {props.description || 'Décrivez-mois SVP !'}
                    </Typography>
               
                    <Stack direction='row' spacing={1} style={{marginTop:'2vh'}}>
                        <AccessTimeIcon />
                        <Typography variant="body2">
                            {props.time || 'Temps inconnus'}
                        </Typography>
                        <Box sx={{ flexGrow: 1 }} />
                        { props.complete ? <TaskAltRoundedIcon color='success' /> : null }
                    </Stack>
                </Card>
            </Link>
        </Grid>
    )
}

export default LessonCard;