import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { dark, materialLight } from 'react-syntax-highlighter/dist/esm/styles/prism';
import ReactMarkdown from 'react-markdown';

function RenderMarkdown(props) {
    return (
        <ReactMarkdown children={props.content}
            // Copier de https://github.com/remarkjs/react-markdown#use-custom-components-syntax-highlight
            components={{
                code({ node, inline, className, children, ...p }) {
                    const match = /language-(\w+)/.exec(className || '')
                    return !inline && match ? (
                        <SyntaxHighlighter 
                            {...p}
                            children={String(children).replace(/\n$/, '')}
                            style={props.darkTheme ? dark : materialLight}
                            language={match[1]}
                            PreTag="div"
                            customStyle={{padding:'0px', margin:'0px'}}
                        />
                    ) : (
                        <code {...p} className={className}>
                            {props.content}
                        </code>
                    )
                }
            }} />
    )
}

export default RenderMarkdown;