import { AppBar, Button, Divider, Toolbar, Typography, Box, Switch } from '@mui/material';
import React from 'react';
import { Link } from 'react-router-dom'



function Header(props) {

    const toggleDarkTheme = () => {
        props.setDarkTheme(!props.darkTheme)
    }

    return (
        <Box style={{ marginBottom: '1vh', marginTop: '10px', height: '10vh' }} sx={{ flexGrow: 1 }}>
            <AppBar>
                <Toolbar>
                    <Typography variant='h4' style={{ marginRight: '20px' }}>
                        {props.pageTitle || 'Cours'}
                    </Typography>
                    <Box sx={{ flexGrow: 1 }} />
                    <Link to='/' style={{ color: 'inherit' }}>
                        <Button variant='secondary'><Typography>Accueil</Typography></Button>
                    </Link>
                    <Divider orientation='vertical' flexItem sx={{margin: '10px'}}/>
                    <Typography>Thème sombre</Typography>
                    <Switch label='Thème sombre' color='secondary' checked={props.darkTheme} onChange={() => toggleDarkTheme()} />
                </Toolbar>
            </AppBar>
            <Divider />
        </Box >
    );
}

export default Header;