import { Typography } from "@mui/material";
import CodeSnippet from "./CodeSnippet";

function EnrichedLabel(props) {
    const content = props.text
    let label, language = null

    if (content.startsWith('!!')) {
        const contentParts = content.split('|')
        language = contentParts[0].substr(2)
        label = contentParts[1]
    } else {
        label = content
    }

    if (language === null) {
        return (
            <Typography>{label}</Typography>
        )
    } else {
        return <CodeSnippet language={language} content={label} darkTheme={props.darkTheme}/>
    }

}

export default EnrichedLabel;