import MenuCourseCard from './MenuCourseCard'
import Stack from '@mui/material/Stack'
import Divider from '@mui/material/Divider'
import Typography from '@mui/material/Typography'
import courses from '../data/courses'

function CourseSelection() {
    return (
        <Stack spacing={1}>
            <Typography variant="h6">
                Cours
            </Typography>

            {courses.filter(element => element.category === 'class').map(element =>
                 (< MenuCourseCard key={element.courseUrl} courseName={element.title} acronym={element.acronym} courseUrl={element.courseUrl} />))}

            <Divider />
            <Typography variant="h6">
                Ressources
            </Typography>

            {courses.filter(element => element.category === 'course').map(element =>
                 (< MenuCourseCard key={element.courseUrl} courseName={element.title} hideDetails courseUrl={element.courseUrl} />))}
        </Stack>
    );
}

export default CourseSelection;