import { Alert, FormControl, FormLabel, Grid, RadioGroup, FormControlLabel, Radio } from "@mui/material";
import { useEffect, useState } from "react";
import EnrichedLabel from "./EnrichedLabel";

function Question(props) {
    const [chosenValue, setChosenValue] = useState(null)
    const [correctAnswer, setCorrectAnswer] = useState(false)
    const [retroMessage, setRetroMessage] = useState("")
    const [displayRetro, setDisplayRetro] = useState(false)

    useEffect(() => {
        if (chosenValue !== null && chosenValue >= 0 && props.questionData.choix.length > chosenValue) {
            const answer = props.questionData.choix[chosenValue]
            setCorrectAnswer(answer.correct)
            setRetroMessage(answer.retro)
            setDisplayRetro(true)
        }
    }, [chosenValue, props.questionData])

    return (
        <Grid item xs={6}>
            <FormControl >
                <FormLabel>{props.questionData.enonce}</FormLabel>
                <RadioGroup defaultValue={null}>
                    {props.questionData.choix.map((choix, idx) => <FormControlLabel key={idx} value={idx} control={<Radio />}
                        label={<EnrichedLabel darkTheme={props.darkTheme} text={choix.text} />} onChange={() => {
                            props.onQuestionAnswered(choix.correct, chosenValue === null || props.questionData.choix[chosenValue].correct === choix.correct)
                            setChosenValue(idx);
                        }} />)}
                </RadioGroup>
                {displayRetro ? (
                    <Alert severity={correctAnswer ? "success" : "error"} variant="outlined">
                        {retroMessage}
                    </Alert>) : <Alert severity="info" variant="outlined" sx={{ width: '100%' }}>Veuillez choisir une réponse</Alert>}
            </FormControl >
        </Grid>

    )
}

export default Question;

