import LessonCard from '../components/LessonCard'
import { Grid } from '@mui/material';
import React, { useEffect } from 'react';
import { useParams, useOutletContext } from 'react-router-dom';

import courses from '../data/courses';

function CourseIndex() {
    const { courseUrl } = useParams()
    const element = courses.find(e => e.courseUrl === courseUrl)
    const { setPageTitle } = useOutletContext()

    useEffect(() => {
        setPageTitle(element.title)
    }, [element.title, setPageTitle])

    const checkIfComplete = (lessonUrl) => {
        const item = localStorage.getItem(courseUrl + '/' + lessonUrl);  
        return item !== null && item !== "false";
    }

    return (
        <Grid container spacing={2}>
            {element.lessons.map((lesson, idx) => (<LessonCard key={idx} title={lesson.title} description={lesson.description}
                time={lesson.time} lessonURL={lesson.lessonUrl} complete={checkIfComplete(lesson.lessonUrl)} />))}
        </Grid>
    )
}

export default CourseIndex;