import { Stack, Typography, Fab, Box } from "@mui/material";
import { useEffect, useState, useCallback  } from "react";
import { useOutletContext, useParams, useNavigate } from "react-router-dom";

import Loading from "../components/Loading";
import Quiz from "../components/Quiz";
import courses from "../data/courses";
import RenderMarkdown from "../components/RenderMarkdown";
import TaskAltRoundedIcon from "@mui/icons-material/TaskAltRounded"

function LessonPage() {
    const { courseUrl, lessonUrl } = useParams()
    const { setPageTitle, darkTheme } = useOutletContext()
    const [content, setContent] = useState("")
    const [error, setError] = useState(false)
    const [loading, setLoading] = useState(true)
    const course = courses.find(c => c.courseUrl === courseUrl)
    const lessonIdx = course.lessons.findIndex(l => l.lessonUrl === lessonUrl)
    const lessonCount = course.lessons.length
    const lesson = course.lessons[lessonIdx]
    let navigate = useNavigate()

    const checkIfCompleted = useCallback(() => {
        const val = localStorage.getItem(courseUrl + '/' + lessonUrl)
        return val !== null && val !== "false"
    }, [courseUrl, lessonUrl])


    const [completed, setCompleted] = useState(checkIfCompleted())

    const markAsCompleted = () => {
        setCompleted(true)
    }

    useEffect(() => {
        try {
            const file = require('../data/' + courseUrl + '/' + lessonUrl + '.md')

            fetch(file)
                .then(response => response.text())
                .then(text => setContent(text))
                .catch(e => setError(e))
        } catch (exception) {
            setError(exception.message)
        }
        setLoading(false)
    }, [courseUrl, lessonUrl, setPageTitle])

    useEffect(() => {
        if (lesson !== null) {
            setPageTitle(lesson.title)
        }

        setCompleted(checkIfCompleted())
    }, [lesson, setPageTitle, setCompleted, checkIfCompleted])


    const redirectToPrevious = () => {
        if (lessonIdx === 0) {
            return navigate('/cours/' + courseUrl)
        } else {
            return navigate('/cours/' + courseUrl + '/' + course.lessons[lessonIdx - 1].lessonUrl)
        }
    }

    const redirectToNext = () => {
        if (lessonIdx === lessonCount - 1) {
            return navigate('/')
        } else {
            return navigate('/cours/' + courseUrl + '/' + course.lessons[lessonIdx + 1].lessonUrl)
        }
    }

    useEffect(() => {
        localStorage.setItem(courseUrl + '/' + lessonUrl, completed)
    }, [completed, courseUrl, lessonUrl])



    if (loading) {
        return <Loading />
    } else if (error !== false) {
        return <Typography>Erreur lors du chargement. {error}</Typography>
    } else {
        return (
            <Stack spacing={5}>
                <RenderMarkdown content={content} darkTheme={darkTheme} />
                {lesson.quiz ? <Quiz courseUrl={courseUrl} lessonUrl={lessonUrl} darkTheme={darkTheme} /> : null}

                <Stack spacing={10} direction='row' justifyContent='space-between'>
                    <Fab variant="extended" color='secondary' onClick={redirectToPrevious}>
                        {lessonIdx === 0 ? "Revenir à la liste des leçons" : "Leçon précédente"}
                    </Fab>
                    <Fab variant='extended' color={completed ? 'disabled' : 'success'} onClick={markAsCompleted}>
                        <Stack direction='row'>
                            Marquer comme complétée
                            <Box sx={{ width: '30px' }} />
                            <TaskAltRoundedIcon />
                        </Stack>
                    </Fab>
                    <Fab variant="extended" color='secondary' onClick={redirectToNext}>
                        {lessonIdx === lessonCount - 1 ? "Revenir à la liste des cours" : "Leçon suivante"}
                    </Fab>
                </Stack>
            </Stack >
        )
    }
}

export default LessonPage;