import { Typography } from "@mui/material";
import { useEffect } from "react";
import { Link, useOutletContext } from 'react-router-dom';

function Error() {

    const setPageTitle = useOutletContext()
    
    useEffect(() => {
        setPageTitle('Ce n\'est pas la page que vous recherchez')
    }, [setPageTitle])
    
    return (
        <Typography variant="subtitle">Tout est beau, vous pouvez retourner à l'<Link to='/'>accueil</Link>.</Typography>
    )
}

export default Error;