import React, { useEffect } from 'react';
import { BrowserRouter, Route, Routes } from 'react-router-dom';
import './App.css';
import LessonPage from './pages/LessonPage';
import CourseIndex from './pages/CourseIndex';
import Error from './pages/Error';
import Home from './pages/Home';
import Layout from './pages/Layout';
import { useState } from 'react';

import '@fontsource/roboto/300.css';
import '@fontsource/roboto/400.css';
import '@fontsource/roboto/500.css';
import '@fontsource/roboto/700.css';


import { ThemeProvider, createTheme } from '@mui/material/styles';
import CssBaseline from '@mui/material/CssBaseline';
import ScrollToTop from './components/ScrollToTop';

const darkThemeCSS = createTheme({
  palette: {
    mode: 'dark',
  },
});
const lightThemeCSS = createTheme({
  palette: {
    mode: 'light',
  },
});

function loadDarkThemeValue() {
   // Ce n'est pas un langage de prog, c'est une joke !
  return localStorage.getItem('DarkTheme') === "true"
}

function App() {
  const [darkTheme, setDarkTheme] = useState(loadDarkThemeValue())

  useEffect(() => {
    localStorage.setItem('DarkTheme', darkTheme.toString())
  }, [darkTheme])


  return (
    <ThemeProvider theme={darkTheme ? darkThemeCSS : lightThemeCSS}>
      <CssBaseline />
      <BrowserRouter>
        <ScrollToTop />
        <Routes>
          <Route path='*' element={<Layout setDarkTheme={setDarkTheme} darkTheme={darkTheme} />}>
            <Route index element={<Home />} />
            <Route path="*" element={<Error />} />
            <Route path='cours/:courseUrl/:lessonUrl' element={<LessonPage />} />
            <Route path='cours/:courseUrl' element={<CourseIndex />} />
          </Route>
        </Routes>
      </BrowserRouter >
    </ThemeProvider>
  );
}

export default App;
